 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 const string modelId = "gpt-4o-mini-2024-07-18";

 // --- Tools ---
 var researchTools = new ResearchTools();

 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(researchTools.SearchWeb),
     AIFunctionFactory.Create(researchTools.SaveNote),
     AIFunctionFactory.Create(researchTools.GetNotes),
 };

 // --- Chat client with automatic function invocation ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()
     .Build();

 // --- Agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research assistant. When given a topic:
         1. Use SearchWeb 2-3 times with different queries to gather information.
         2. Use SaveNote to record each key finding with a short title and the detail.
         3. After gathering enough information, use GetNotes to review all findings.
         4. Provide a well-structured summary with sections and cite your sources.
         Be thorough but concise.
         """,
     name: "ResearchAgent",
     description: "Researches topics using web search and note-taking",
     tools: tools);

 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 2048,
 });

 // --- Interactive loop ---
 Console.WriteLine("=== Research Agent ===");
 Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

 while (true)
 {
     Console.Write("> ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     researchTools.ClearNotes();

     Console.WriteLine($"\nResearching: {topic}\n");

     var session = await agent.CreateSessionAsync();
     var response = await agent.RunAsync(
         $"Research the following topic and provide a comprehensive summary: {topic}",
         session,
         runOptions);

     foreach (var message in response.Messages)
     {
         if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
         {
             Console.WriteLine(message.Text);
         }
     }

     Console.WriteLine();
 }

 Console.WriteLine("Goodbye!");

 // --- Tool implementations ---

 public sealed class ResearchTools
 {
     private readonly ConcurrentDictionary<string, string> _notes = new();

     /// <summary>Searches the web for information on a query.</summary>
     [Description("Searches the web for information. Returns a list of results with titles, snippets, and URLs.")]
     public string SearchWeb(
         [Description("The search query")] string query)
     {
         Console.WriteLine($"  [Tool] SearchWeb: \"{query}\"");

         // Simulated search results — swap with a real search API (Bing, Google, etc.)
         var results = GenerateSearchResults(query);
         return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
     }

     /// <summary>Saves a research note.</summary>
     [Description("Saves a research note for later reference. Use to record key findings.")]
     public string SaveNote(
         [Description("Short title for the note")] string title,
         [Description("Detailed content of the note")] string content)
     {
         _notes[title] = content;
         Console.WriteLine($"  [Tool] SaveNote: \"{title}\"");
         return $"Note saved: {title}";
     }

     /// <summary>Retrieves all saved research notes.</summary>
     [Description("Retrieves all previously saved research notes.")]
     public string GetNotes()
     {
         Console.WriteLine("  [Tool] GetNotes");
         if (_notes.IsEmpty)
             return "No notes saved yet.";

         var notes = _notes.Select(kv => new { Title = kv.Key, Content = kv.Value });
         return JsonSerializer.Serialize(notes, new JsonSerializerOptions { WriteIndented = true });
     }

     public void ClearNotes() => _notes.Clear();

     private static List<SearchResult> GenerateSearchResults(string query)
     {
         // Deterministic simulated results based on query hash for demo purposes.
         // Replace this method body with a real search API call for production use.
         var hash = Math.Abs(query.GetHashCode());
         var domain = (hash % 3) switch
         {
             0 => "wikipedia.org",
             1 => "arxiv.org",
             _ => "nature.com",
         };

         return
         [
             new($"Overview of {query}",
                 $"A comprehensive overview covering the key aspects of {query}, "
                 + "including history, current developments, and future outlook.",
                 $"https://en.{domain}/wiki/{Uri.EscapeDataString(query)}"),

             new($"Recent advances in {query}",
                 $"Researchers have made significant progress in {query}. "
                 + "New findings suggest promising applications in multiple fields.",
                 $"https://{domain}/articles/{hash % 10000}"),

             new($"{query}: practical applications",
                 $"This article explores real-world applications of {query}, "
                 + "with case studies from industry and academia.",
                 $"https://www.{domain}/review/{query.Replace(' ', '-').ToLowerInvariant()}"),
         ];
     }
 }

 public sealed record SearchResult(string Title, string Snippet, string Url);
